const CARDS = [
  {id:1,emoji:'⚖️',ar:{title:'الوسطية الإسلامية',desc:'الإسلام لا رأسمالي ولا اشتراكي. هو نظام وسط يأخذ أفضل ما في كل نظام ويتجنب عيوبه. يحمي الملكية الفردية ويفرض العدالة الاجتماعية.',verse:'وَكَذَٰلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا',verseRef:'البقرة: ١٤٣',lesson:'الوسطية منهج الإسلام في كل شيء'},en:{title:'Islamic Moderation',desc:'Islam is neither capitalist nor socialist. It is a middle system that takes the best of each and avoids their flaws. It protects private property and enforces social justice.',verse:'And thus We have made you a moderate nation',verseRef:'Al-Baqarah: 143',lesson:'Moderation is Islam\'s methodology in everything'},fr:{title:'La Moderation Islamique',desc:'L\'Islam n\'est ni capitaliste ni socialiste. C\'est un systeme intermediaire qui prend le meilleur de chacun et evite leurs defauts.',verse:'Ainsi Nous avons fait de vous une communaute du juste milieu',verseRef:'Al-Baqarah: 143',lesson:'La moderation est la methodologie de l\'Islam en tout'}},
  {id:2,emoji:'🏠',ar:{title:'الملكية الفردية حق مشروع',desc:'الإسلام يحمي حق الملكية الفردية ويعتبره حقاً طبيعياً. لكنه يقيّده بالكسب الحلال ويفرض عليه حقوقاً للمجتمع.',verse:'لِلرِّجَالِ نَصِيبٌ مِّمَّا اكْتَسَبُوا',verseRef:'النساء: ٣٢',lesson:'الملكية حق مقيّد بالعدل لا مطلق'},en:{title:'Private Property Is Legitimate',desc:'Islam protects private property as a natural right. But it restricts it to lawful earnings and imposes social obligations.',verse:'For men is a share of what they have earned',verseRef:'An-Nisa: 32',lesson:'Property is a right bounded by justice, not absolute'},fr:{title:'La Propriete Privee Est Legitime',desc:'L\'Islam protege la propriete privee comme un droit naturel. Mais il la restreint aux gains licites et impose des obligations sociales.',verse:'Aux hommes revient une part de ce qu\'ils ont acquis',verseRef:'An-Nisa: 32',lesson:'La propriete est un droit limite par la justice, pas absolu'}},
  {id:3,emoji:'💰',ar:{title:'الزكاة نظام توزيع',desc:'الزكاة ليست صدقة تطوعية بل نظام إلزامي لتوزيع الثروة. هي حق الفقير في مال الغني، فُرضت قبل أي نظام ضريبي حديث.',verse:'وَالَّذِينَ فِي أَمْوَالِهِمْ حَقٌّ مَّعْلُومٌ',verseRef:'المعارج: ٢٤',lesson:'الزكاة نظام عدالة اجتماعية سبق عصره'},en:{title:'Zakat: A Distribution System',desc:'Zakat is not voluntary charity but a mandatory wealth distribution system. It is the poor\'s right in the wealthy\'s money, established before any modern tax system.',verse:'And those in whose wealth is a known right',verseRef:'Al-Ma\'arij: 24',lesson:'Zakat is a social justice system ahead of its time'},fr:{title:'La Zakat : Un Systeme de Distribution',desc:'La Zakat n\'est pas une charite volontaire mais un systeme obligatoire de distribution des richesses. C\'est le droit du pauvre dans la richesse du riche.',verse:'Et ceux dans les biens desquels il y a un droit connu',verseRef:'Al-Ma\'arij: 24',lesson:'La Zakat est un systeme de justice sociale en avance sur son temps'}},
  {id:4,emoji:'🏛️',ar:{title:'دور الدولة في الاقتصاد',desc:'الدولة في الإسلام تراقب السوق وتمنع الاحتكار والغش لكنها لا تحتكر الاقتصاد. التوازن بين حرية السوق ورقابة الدولة.',verse:'وَلَا تَبْخَسُوا النَّاسَ أَشْيَاءَهُمْ',verseRef:'الشعراء: ١٨٣',lesson:'الدولة حارسة للعدل لا محتكرة للثروة'},en:{title:'The State\'s Role in Economics',desc:'The state in Islam monitors markets and prevents monopoly and fraud but does not monopolize the economy. Balance between market freedom and state oversight.',verse:'And do not deprive people of their due',verseRef:'Ash-Shu\'ara: 183',lesson:'The state guards justice, not monopolizes wealth'},fr:{title:'Le Role de l\'Etat dans l\'Economie',desc:'L\'Etat en Islam surveille les marches et empeche le monopole et la fraude mais ne monopolise pas l\'economie.',verse:'Ne privez pas les gens de ce qui leur est du',verseRef:'Ash-Shu\'ara: 183',lesson:'L\'Etat garde la justice, ne monopolise pas la richesse'}},
  {id:5,emoji:'🤝',ar:{title:'التكافل الاجتماعي',desc:'الإسلام بنى نظام تكافل اجتماعي شامل: الزكاة، الوقف، الصدقة، كفالة اليتيم، إطعام المسكين — كلها آليات لمحاربة الفقر.',verse:'وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ',verseRef:'المائدة: ٢',lesson:'التكافل ركن من أركان المجتمع الإسلامي'},en:{title:'Social Solidarity',desc:'Islam built a comprehensive social solidarity system: zakat, waqf, charity, orphan care, feeding the poor — all mechanisms to fight poverty.',verse:'And cooperate in righteousness and piety',verseRef:'Al-Ma\'idah: 2',lesson:'Solidarity is a pillar of Islamic society'},fr:{title:'La Solidarite Sociale',desc:'L\'Islam a bati un systeme complet de solidarite sociale : zakat, waqf, charite, soin des orphelins — tous des mecanismes contre la pauvrete.',verse:'Entraidez-vous dans la bienfaisance et la piete',verseRef:'Al-Ma\'idah: 2',lesson:'La solidarite est un pilier de la societe islamique'}},
  {id:6,emoji:'📊',ar:{title:'توزيع الثروة',desc:'الإسلام يرفض تركّز الثروة في أيدي قلة. الزكاة والمواريث والصدقات كلها آليات لضمان تدوير المال في المجتمع.',verse:'كَيْ لَا يَكُونَ دُولَةً بَيْنَ الْأَغْنِيَاءِ مِنكُمْ',verseRef:'الحشر: ٧',lesson:'تركّز الثروة ظلم يرفضه الإسلام'},en:{title:'Wealth Distribution',desc:'Islam rejects concentration of wealth. Zakat, inheritance laws, and charity are all mechanisms to ensure wealth circulation in society.',verse:'So that it will not be a perpetual distribution among the rich',verseRef:'Al-Hashr: 7',lesson:'Wealth concentration is injustice that Islam rejects'},fr:{title:'Distribution des Richesses',desc:'L\'Islam rejette la concentration des richesses. Zakat, lois de succession et charite assurent la circulation des richesses.',verse:'Afin que cela ne circule pas seulement entre les riches',verseRef:'Al-Hashr: 7',lesson:'La concentration des richesses est une injustice que l\'Islam rejette'}},
  {id:7,emoji:'🚫',ar:{title:'تحريم الربا',desc:'الإسلام حرّم الربا لأنه يزيد الغني غنى والفقير فقراً. البديل الإسلامي: المشاركة في الربح والخسارة والتمويل الحلال.',verse:'وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا',verseRef:'البقرة: ٢٧٥',lesson:'الربا يدمر العدالة الاجتماعية'},en:{title:'Prohibition of Usury',desc:'Islam prohibited usury because it makes the rich richer and the poor poorer. The Islamic alternative: profit-and-loss sharing and halal financing.',verse:'God has permitted trade and forbidden usury',verseRef:'Al-Baqarah: 275',lesson:'Usury destroys social justice'},fr:{title:'Interdiction de l\'Usure',desc:'L\'Islam a interdit l\'usure car elle enrichit les riches et appauvrit les pauvres. L\'alternative islamique : partage des profits et pertes.',verse:'Dieu a permis le commerce et interdit l\'usure',verseRef:'Al-Baqarah: 275',lesson:'L\'usure detruit la justice sociale'}},
  {id:8,emoji:'🏗️',ar:{title:'الوقف: الاستثمار الاجتماعي',desc:'الوقف نظام إسلامي فريد: تحبيس مال أو عقار لخدمة المجتمع للأبد. بنى المستشفيات والمدارس والمكتبات قبل أي نظام خيري حديث.',verse:'لَن تَنَالُوا الْبِرَّ حَتَّىٰ تُنفِقُوا مِمَّا تُحِبُّونَ',verseRef:'آل عمران: ٩٢',lesson:'الوقف استثمار أبدي في خدمة المجتمع'},en:{title:'Waqf: Social Investment',desc:'Waqf is a unique Islamic system: endowing property for community service forever. It built hospitals, schools, and libraries before any modern charity system.',verse:'You will not attain righteousness until you spend from what you love',verseRef:'Aal-Imran: 92',lesson:'Waqf is an eternal investment in community service'},fr:{title:'Le Waqf : Investissement Social',desc:'Le Waqf est un systeme islamique unique : consacrer un bien au service de la communaute pour toujours. Il a bati hopitaux, ecoles et bibliotheques.',verse:'Vous n\'atteindrez la piete que si vous depensez de ce que vous aimez',verseRef:'Aal-Imran: 92',lesson:'Le Waqf est un investissement eternel dans le service communautaire'}},
  {id:9,emoji:'👷',ar:{title:'كرامة العامل',desc:'الإسلام كرّم العامل وأمر بإعطائه أجره قبل أن يجف عرقه. حقوق العمال في الإسلام سبقت كل قوانين العمل الحديثة.',verse:'وَقُلِ اعْمَلُوا فَسَيَرَى اللَّهُ عَمَلَكُمْ',verseRef:'التوبة: ١٠٥',lesson:'العمل عبادة والعامل مكرّم في الإسلام'},en:{title:'Worker Dignity',desc:'Islam honored workers and commanded paying their wages before their sweat dries. Workers\' rights in Islam preceded all modern labor laws.',verse:'And say: Work, for God will see your work',verseRef:'At-Tawbah: 105',lesson:'Work is worship and workers are honored in Islam'},fr:{title:'La Dignite du Travailleur',desc:'L\'Islam a honore les travailleurs et ordonne de les payer avant que leur sueur ne seche. Les droits des travailleurs en Islam ont precede toutes les lois modernes.',verse:'Dis : Oeuvrez, car Dieu verra votre oeuvre',verseRef:'At-Tawbah: 105',lesson:'Le travail est une adoration et les travailleurs sont honores'}},
  {id:10,emoji:'🌾',ar:{title:'الأرض لمن يزرعها',desc:'الإسلام شجّع إحياء الأرض الموات ومنح حق ملكيتها لمن يزرعها. هذا المبدأ حقق العدالة الزراعية قبل أي إصلاح أرضي حديث.',verse:'مَا مِنْ مُسْلِمٍ يَغْرِسُ غَرْسًا فَيَأْكُلُ مِنْهُ إِنْسَانٌ أَوْ طَيْرٌ إِلَّا كَانَ لَهُ صَدَقَةً',verseRef:'حديث - البخاري',lesson:'إحياء الأرض من أعظم العبادات'},en:{title:'Land Belongs to Those Who Cultivate It',desc:'Islam encouraged reviving dead land and granted ownership to those who cultivate it. This principle achieved agricultural justice before any modern land reform.',verse:'No Muslim plants a tree from which a person or bird eats except it is charity for them',verseRef:'Hadith - Bukhari',lesson:'Reviving land is among the greatest acts of worship'},fr:{title:'La Terre Appartient a Celui qui la Cultive',desc:'L\'Islam a encourage la mise en valeur des terres mortes et accorde la propriete a ceux qui les cultivent.',verse:'Tout musulman qui plante un arbre dont mange un homme ou un oiseau en tire une aumone',verseRef:'Hadith - Bukhari',lesson:'Mettre en valeur la terre est parmi les plus grands actes d\'adoration'}},
  {id:11,emoji:'🚫',ar:{title:'تحريم الاحتكار',desc:'الإسلام حرّم الاحتكار لأنه يضر بالمستهلك ويرفع الأسعار ظلماً. السوق الحرة في الإسلام حرة من الغش والاحتكار.',verse:'لَا يَحْتَكِرُ إِلَّا خَاطِئٌ',verseRef:'حديث - مسلم',lesson:'الاحتكار خطيئة اقتصادية واجتماعية'},en:{title:'Prohibition of Monopoly',desc:'Islam prohibited monopoly because it harms consumers and unjustly raises prices. The free market in Islam is free from fraud and monopoly.',verse:'None hoards except a sinner',verseRef:'Hadith - Muslim',lesson:'Monopoly is an economic and social sin'},fr:{title:'Interdiction du Monopole',desc:'L\'Islam a interdit le monopole car il nuit aux consommateurs et augmente injustement les prix.',verse:'Seul un pecheur stocke pour creer la rarete',verseRef:'Hadith - Muslim',lesson:'Le monopole est un peche economique et social'}},
  {id:12,emoji:'📜',ar:{title:'نظام المواريث',desc:'نظام المواريث في الإسلام يوزع الثروة على الأقارب تلقائياً بعد الوفاة. هذا يمنع تراكم الثروة في عائلة واحدة لأجيال.',verse:'لِّلرِّجَالِ نَصِيبٌ مِّمَّا تَرَكَ الْوَالِدَانِ وَالْأَقْرَبُونَ',verseRef:'النساء: ٧',lesson:'المواريث آلية ذكية لتوزيع الثروة'},en:{title:'Inheritance System',desc:'Islamic inheritance automatically distributes wealth among relatives upon death. This prevents wealth accumulation in one family for generations.',verse:'For men is a share of what parents and close relatives leave',verseRef:'An-Nisa: 7',lesson:'Inheritance is an intelligent mechanism for wealth distribution'},fr:{title:'Le Systeme de Succession',desc:'La succession islamique distribue automatiquement la richesse parmi les proches apres le deces. Cela empeche l\'accumulation dans une seule famille.',verse:'Aux hommes revient une part de ce que laissent les parents et les proches',verseRef:'An-Nisa: 7',lesson:'La succession est un mecanisme intelligent de distribution des richesses'}},
  {id:13,emoji:'🤲',ar:{title:'الإنفاق في سبيل الله',desc:'الإنفاق في الإسلام ليس خسارة بل استثمار عند الله. من ينفق ماله في الخير يزداد بركة ولا ينقص.',verse:'مَّثَلُ الَّذِينَ يُنفِقُونَ أَمْوَالَهُمْ فِي سَبِيلِ اللَّهِ كَمَثَلِ حَبَّةٍ أَنبَتَتْ سَبْعَ سَنَابِلَ',verseRef:'البقرة: ٢٦١',lesson:'الإنفاق استثمار لا خسارة'},en:{title:'Spending in God\'s Way',desc:'Spending in Islam is not a loss but an investment with God. Those who spend their wealth for good increase in blessing.',verse:'The example of those who spend their wealth in the way of God is like a seed that grows seven ears',verseRef:'Al-Baqarah: 261',lesson:'Spending is investment, not loss'},fr:{title:'Depenser dans le Chemin de Dieu',desc:'Depenser en Islam n\'est pas une perte mais un investissement aupres de Dieu. Ceux qui depensent leurs biens pour le bien augmentent en benediction.',verse:'Ceux qui depensent leurs biens dans le chemin de Dieu sont comme un grain qui produit sept epis',verseRef:'Al-Baqarah: 261',lesson:'Depenser est un investissement, pas une perte'}},
  {id:14,emoji:'🏪',ar:{title:'حرية التجارة',desc:'الإسلام أباح التجارة الحرة وشجّعها. التاجر الصدوق الأمين مع النبيين والصديقين يوم القيامة.',verse:'وَأَحَلَّ اللَّهُ الْبَيْعَ',verseRef:'البقرة: ٢٧٥',lesson:'التجارة الحلال عبادة وطريق للرزق'},en:{title:'Freedom of Trade',desc:'Islam permitted and encouraged free trade. The honest, trustworthy merchant will be with the prophets and the truthful on the Day of Judgment.',verse:'And God has permitted trade',verseRef:'Al-Baqarah: 275',lesson:'Lawful trade is worship and a path to livelihood'},fr:{title:'Liberte du Commerce',desc:'L\'Islam a permis et encourage le libre commerce. Le commercant honnete et fiable sera avec les prophetes au Jour du Jugement.',verse:'Et Dieu a permis le commerce',verseRef:'Al-Baqarah: 275',lesson:'Le commerce licite est une adoration et un chemin vers la subsistance'}},
  {id:15,emoji:'🕊️',ar:{title:'الحرية الاقتصادية',desc:'الإسلام يمنح حرية اقتصادية مسؤولة. الفرد حر في اختيار عمله ونشاطه الاقتصادي ضمن حدود الحلال.',verse:'هُوَ الَّذِي جَعَلَ لَكُمُ الْأَرْضَ ذَلُولًا فَامْشُوا فِي مَنَاكِبِهَا',verseRef:'الملك: ١٥',lesson:'الحرية الاقتصادية حق مقيّد بالحلال'},en:{title:'Economic Freedom',desc:'Islam grants responsible economic freedom. Individuals are free to choose their work and economic activity within the bounds of what is lawful.',verse:'It is He who made the earth easy for you, so walk among its slopes',verseRef:'Al-Mulk: 15',lesson:'Economic freedom is a right bounded by lawfulness'},fr:{title:'La Liberte Economique',desc:'L\'Islam accorde une liberte economique responsable. Les individus sont libres de choisir leur travail dans les limites du licite.',verse:'C\'est Lui qui a rendu la terre docile, marchez donc dans ses sentiers',verseRef:'Al-Mulk: 15',lesson:'La liberte economique est un droit limite par le licite'}},
  {id:16,emoji:'🌍',ar:{title:'الاقتصاد الإسلامي عالمي',desc:'النظام الاقتصادي الإسلامي ليس محلياً بل عالمي. يصلح لكل زمان ومكان لأنه مبني على مبادئ ثابتة ومرنة في التطبيق.',verse:'وَمَا أَرْسَلْنَاكَ إِلَّا رَحْمَةً لِّلْعَالَمِينَ',verseRef:'الأنبياء: ١٠٧',lesson:'الاقتصاد الإسلامي يصلح لكل عصر'},en:{title:'Islamic Economics Is Universal',desc:'The Islamic economic system is not local but universal. It works for all times and places because it is built on fixed principles with flexible application.',verse:'And We have not sent you except as a mercy to the worlds',verseRef:'Al-Anbiya: 107',lesson:'Islamic economics works for every era'},fr:{title:'L\'Economie Islamique Est Universelle',desc:'Le systeme economique islamique n\'est pas local mais universel. Il fonctionne pour tous les temps et lieux car il est bati sur des principes fixes avec une application flexible.',verse:'Nous ne t\'avons envoye que comme misericorde pour les mondes',verseRef:'Al-Anbiya: 107',lesson:'L\'economie islamique fonctionne pour chaque epoque'}},
  {id:17,emoji:'💎',ar:{title:'الرزق من الله',desc:'الإسلام يعلّم أن الرزق بيد الله. هذا لا يعني الكسل بل يعني العمل مع التوكل والقناعة بما قسم الله.',verse:'وَفِي السَّمَاءِ رِزْقُكُمْ وَمَا تُوعَدُونَ',verseRef:'الذاريات: ٢٢',lesson:'التوكل على الله مع السعي هو الطريق'},en:{title:'Provision Is from God',desc:'Islam teaches that provision is in God\'s hands. This does not mean laziness but working with trust and contentment with what God has decreed.',verse:'And in the heaven is your provision and whatever you are promised',verseRef:'Adh-Dhariyat: 22',lesson:'Trust in God with effort is the way'},fr:{title:'La Subsistance Vient de Dieu',desc:'L\'Islam enseigne que la subsistance est entre les mains de Dieu. Cela ne signifie pas la paresse mais travailler avec confiance et contentement.',verse:'Dans le ciel se trouve votre subsistance et ce qui vous est promis',verseRef:'Adh-Dhariyat: 22',lesson:'La confiance en Dieu avec l\'effort est la voie'}},
  {id:18,emoji:'📖',ar:{title:'العلم والاقتصاد',desc:'الإسلام ربط بين العلم والاقتصاد. طلب العلم فريضة، والعالم المسلم يسهم في تطوير الاقتصاد بعلمه وابتكاره.',verse:'هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لَا يَعْلَمُونَ',verseRef:'الزمر: ٩',lesson:'العلم محرّك الاقتصاد الحقيقي'},en:{title:'Knowledge and Economics',desc:'Islam linked knowledge and economics. Seeking knowledge is obligatory, and a Muslim scholar contributes to economic development through learning and innovation.',verse:'Are those who know equal to those who do not know?',verseRef:'Az-Zumar: 9',lesson:'Knowledge is the real engine of economics'},fr:{title:'Le Savoir et l\'Economie',desc:'L\'Islam a lie le savoir et l\'economie. La quete du savoir est obligatoire, et le savant musulman contribue au developpement economique.',verse:'Sont-ils egaux, ceux qui savent et ceux qui ne savent pas ?',verseRef:'Az-Zumar: 9',lesson:'Le savoir est le vrai moteur de l\'economie'}},
  {id:19,emoji:'🌱',ar:{title:'الاستدامة في الإسلام',desc:'الإسلام سبق مفهوم الاستدامة الحديث. نهى عن الإسراف وأمر بحفظ الموارد حتى في الحرب.',verse:'وَلَا تُسْرِفُوا إِنَّهُ لَا يُحِبُّ الْمُسْرِفِينَ',verseRef:'الأنعام: ١٤١',lesson:'الإسراف محرّم حتى في المباح'},en:{title:'Sustainability in Islam',desc:'Islam preceded the modern concept of sustainability. It prohibited waste and commanded preserving resources even during war.',verse:'And do not waste; indeed, He does not like the wasteful',verseRef:'Al-An\'am: 141',lesson:'Wastefulness is prohibited even in what is permissible'},fr:{title:'La Durabilite en Islam',desc:'L\'Islam a precede le concept moderne de durabilite. Il a interdit le gaspillage et ordonne la preservation des ressources.',verse:'Et ne gaspillez pas ; Il n\'aime pas les gaspilleurs',verseRef:'Al-An\'am: 141',lesson:'Le gaspillage est interdit meme dans le permis'}},
  {id:20,emoji:'🕌',ar:{title:'الاقتصاد الإسلامي شامل',desc:'الاقتصاد الإسلامي ليس مجرد أرقام. هو جزء من منظومة شاملة تربط بين العبادة والأخلاق والمعاملات.',verse:'وَابْتَغِ فِيمَا آتَاكَ اللَّهُ الدَّارَ الْآخِرَةَ وَلَا تَنسَ نَصِيبَكَ مِنَ الدُّنْيَا',verseRef:'القصص: ٧٧',lesson:'الاقتصاد الإسلامي يوازن بين الدنيا والآخرة'},en:{title:'Islamic Economics Is Comprehensive',desc:'Islamic economics is not just numbers. It is part of a comprehensive system linking worship, ethics, and transactions.',verse:'Seek through what God has given you the home of the Hereafter, and do not forget your share of this world',verseRef:'Al-Qasas: 77',lesson:'Islamic economics balances this life and the hereafter'},fr:{title:'L\'Economie Islamique Est Complete',desc:'L\'economie islamique n\'est pas que des chiffres. C\'est un systeme complet liant adoration, ethique et transactions.',verse:'Recherche dans ce que Dieu t\'a donne la demeure derniere et n\'oublie pas ta part de ce monde',verseRef:'Al-Qasas: 77',lesson:'L\'economie islamique equilibre cette vie et l\'au-dela'}}
];

