let lang = localStorage.getItem('manahij-lang') || 'ar';
let theme = localStorage.getItem('manahij-theme') || 'ember';
const themes = ['ember','night','sand'];
const themeIcons = ['🟠','🌙','🏜️'];
const themeNames = {ember:'برتقالي',night:'ليل هادئ',sand:'رملي'};
let currentCardIdx = -1;

document.addEventListener('DOMContentLoaded', () => { setTheme(theme); setLang(lang); initTabs(); initSplash(); initScrollTop(); renderHome(); renderCards(); renderComparisons(); renderHabits(); renderQuiz(); renderAbout(); renderHelp(); renderDuas(); initScrollReveal(); initKeyboardNav(); });

function initSplash(){let count=5;const el=document.getElementById('splashCount');const fe=document.getElementById('splashFeatures');if(fe)fe.innerHTML=T[lang].splashFeatures.map((f,i)=>`<div class="splash-feature" style="animation-delay:${0.3+i*0.3}s">${f}</div>`).join('');const iv=setInterval(()=>{count--;if(el)el.textContent=count;if(count<=0){dismissSplash();clearInterval(iv);}},1000);}
function dismissSplash(){const s=document.getElementById('splash');if(s){s.classList.add('hidden');setTimeout(()=>s.style.display='none',500);}playSound('click');}

function setLang(l){lang=l;localStorage.setItem('manahij-lang',l);const isRTL=l==='ar';document.documentElement.lang=l;document.documentElement.dir=isRTL?'rtl':'ltr';document.body.dir=isRTL?'rtl':'ltr';document.querySelectorAll('.lang-opt').forEach(b=>b.classList.toggle('active',b.dataset.lang===l));const t=T[l];const set=(id,val)=>{const el=document.getElementById(id);if(el)el.textContent=val;};set('appTitle',t.appTitle);set('splashSub',t.splashSub);set('splashHint',t.splashHint);set('tabHome',t.tabHome);set('tabCards',t.tabCards);set('tabComparisons',t.tabComparisons);set('tabHabits',t.tabHabits);set('tabQuiz',t.tabQuiz);set('tabAbout',t.tabAbout);set('cardsTitle',t.cardsTitle);set('cardsDesc',t.cardsDesc);set('comparisonsTitle',t.comparisonsTitle);set('comparisonsDesc',t.comparisonsDesc);set('habitsTitle',t.habitsTitle);set('habitsDesc',t.habitsDesc);set('quizTitle',t.quizTitle);set('quizDesc',t.quizDesc);set('helpTitle',t.helpTitle);set('duaPanelTitle',t.duaPanelTitle);set('habitsReset',t.resetBtn);renderHome();renderCards();renderComparisons();renderHabits();renderQuiz();renderAbout();renderHelp();renderDuas();const fe=document.getElementById('splashFeatures');if(fe)fe.innerHTML=T[l].splashFeatures.map((f,i)=>`<div class="splash-feature" style="animation-delay:${0.3+i*0.3}s">${f}</div>`).join('');}

function setTheme(t){theme=t;document.documentElement.dataset.theme=t;localStorage.setItem('manahij-theme',t);const idx=themes.indexOf(t);const el=document.getElementById('themeIcon');if(el)el.textContent=themeIcons[idx];}
function cycleTheme(){const idx=(themes.indexOf(theme)+1)%themes.length;setTheme(themes[idx]);showToast(themeNames[themes[idx]]);playSound('theme');}
function initTabs(){document.querySelectorAll('.tab').forEach(tab=>{tab.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));tab.classList.add('active');const panel=document.getElementById('panel-'+tab.dataset.tab);if(panel)panel.classList.add('active');window.scrollTo({top:0,behavior:'smooth'});playSound('click');});});}

function renderHome(){const t=T[lang];const dayIdx=new Date().getDate()%CARDS.length;const c=CARDS[dayIdx];const cd=c[lang];document.getElementById('dailyCard').innerHTML=`<div class="daily-label">${t.dailyLabel}</div><div class="daily-title">${cd.title}</div><div class="daily-body">${cd.desc}</div><div class="daily-action" onclick="document.querySelector('[data-tab=cards]').click()">${t.tabCards} &#8594;</div>`;const sections=[{icon:'🟠',tab:'cards',title:t.tabCards,desc:lang==='ar'?'٢٠ بطاقة':lang==='fr'?'20 cartes':'20 cards'},{icon:'⚖️',tab:'comparisons',title:t.tabComparisons,desc:lang==='ar'?'تحليل مقارن':lang==='fr'?'Analyse comparative':'Comparative analysis'},{icon:'📋',tab:'habits',title:t.tabHabits,desc:lang==='ar'?'تتبع يومي':lang==='fr'?'Suivi quotidien':'Daily tracking'},{icon:'🤔',tab:'quiz',title:t.tabQuiz,desc:lang==='ar'?'اختبر نفسك':lang==='fr'?'Testez-vous':'Test yourself'},{icon:'📖',tab:'about',title:t.tabAbout,desc:lang==='ar'?'عن الكتاب':lang==='fr'?'Le livre':'The book'}];document.getElementById('homeGrid').innerHTML=sections.map(s=>`<div class="home-card" onclick="document.querySelector('[data-tab=${s.tab}]').click()"><span class="hc-icon">${s.icon}</span><div class="hc-title">${s.title}</div><div class="hc-desc">${s.desc}</div></div>`).join('');}

function renderCards(){const t=T[lang];const sb=`<div class="search-bar"><input type="text" id="cardsSearch" class="search-input" placeholder="${t.searchPlaceholder}" oninput="filterCards(this.value)"><span class="search-icon">🔍</span></div>`;const cards=CARDS.map((c,i)=>{const d=c[lang];return `<div class="principle-card scroll-reveal" id="card-${c.id}" data-search="${d.title.toLowerCase()}"><div class="principle-head" onclick="toggleCard('card-${c.id}')"><span class="principle-num">${c.id}</span><span class="principle-emoji">${c.emoji}</span><span class="principle-title">${d.title}</span><span class="principle-chev">&#9660;</span></div><div class="principle-body"><div class="principle-inner"><p class="principle-desc">${d.desc}</p><div class="verse-box"><div class="verse-arabic">${d.verse}</div><div class="verse-ref">${d.verseRef}</div></div><div class="action-box"><span class="action-icon">💡</span><span>${d.lesson}</span></div><button class="share-btn" onclick="event.stopPropagation();shareCard(${i})"><span class="share-icon">&#128279;</span> ${t.share}</button></div></div></div>`;}).join('');document.getElementById('cardsContainer').innerHTML=sb+cards;}
function filterCards(q){q=q.toLowerCase().trim();document.querySelectorAll('.principle-card').forEach(c=>{const m=!q||(c.dataset.search||'').includes(q)||(c.querySelector('.principle-title')?.textContent.toLowerCase()||'').includes(q);c.style.display=m?'':'none';});}
async function shareCard(idx){const c=CARDS[idx];const d=c[lang];const text=`${c.emoji} ${d.title}\n\n${d.desc}\n\n💡 ${d.lesson}\n\n— الإسلام والمناهج الاشتراكية`;if(navigator.share){try{await navigator.share({title:d.title,text});}catch(e){}}else{try{await navigator.clipboard.writeText(text);showToast(lang==='ar'?'تم النسخ!':lang==='fr'?'Copie !':'Copied!');}catch(e){showToast('Could not copy');}}}

function renderComparisons(){const t=T[lang];document.getElementById('comparisonsContainer').innerHTML=COMPARISONS.map(c=>{const d=c[lang];return `<div class="anxiety-card scroll-reveal"><div class="anxiety-header"><span class="anxiety-emoji">${c.emoji}</span><span class="anxiety-title">${d.topic}</span></div><div class="comparison-box"><div class="comparison-side ghazali-side"><div class="comp-label">${t.islamView}</div><div class="comp-text">${d.islam}</div></div><div class="comparison-side carnegie-side"><div class="comp-label">${t.socialistView}</div><div class="comp-text">${d.socialist}</div></div></div></div>`;}).join('');}

function renderHabits(){const today=new Date().toDateString();let hs=JSON.parse(localStorage.getItem('manahij-habits')||'{}');if(hs.date!==today){updateStreak(hs);hs={date:today,done:[]};localStorage.setItem('manahij-habits',JSON.stringify(hs));}const streak=getStreak();const sHTML=streak>0?`<div class="streak-badge">🔥 ${streak} ${T[lang].streakMsg}</div>`:'';document.getElementById('habitsContainer').innerHTML=HABITS.map((h,i)=>{const d=h[lang];const done=hs.done.includes(i);return `<div class="habit-item ${done?'done':''}" onclick="toggleHabit(${i})"><span class="habit-check">${done?'&#10003;':''}</span><span class="habit-emoji">${h.emoji}</span><div><div class="habit-label">${d.label}</div><div class="habit-source">${d.source}</div></div></div>`;}).join('');const se=document.getElementById('streakBadge');if(se)se.innerHTML=sHTML;updateHabitsProgress(hs);}
function toggleHabit(i){const today=new Date().toDateString();let hs=JSON.parse(localStorage.getItem('manahij-habits')||'{}');if(hs.date!==today)hs={date:today,done:[]};const idx=hs.done.indexOf(i);if(idx>-1)hs.done.splice(idx,1);else hs.done.push(i);localStorage.setItem('manahij-habits',JSON.stringify(hs));renderHabits();playSound(idx>-1?'click':'success');if(hs.done.length===HABITS.length){launchConfetti();showToast(T[lang].allDone);}}
function resetHabits(){localStorage.setItem('manahij-habits',JSON.stringify({date:new Date().toDateString(),done:[]}));renderHabits();showToast(lang==='ar'?'تم إعادة التعيين':lang==='fr'?'Reinitialise':'Reset');}
function updateHabitsProgress(hs){const d=hs.done.length,t=HABITS.length,p=t>0?(d/t*100):0;const f=document.getElementById('habitsFill');const tx=document.getElementById('habitsText');if(f)f.style.width=p+'%';if(tx)tx.textContent=`${d}/${t}`;}
function updateStreak(prev){let sd=JSON.parse(localStorage.getItem('manahij-streak')||'{"count":0,"lastDate":""}');if(prev&&prev.done&&prev.done.length===HABITS.length&&prev.date){const y=new Date();y.setDate(y.getDate()-1);if(prev.date===y.toDateString())sd.count++;else if(prev.date!==new Date().toDateString())sd.count=prev.done.length===HABITS.length?1:0;sd.lastDate=prev.date;}else if(prev&&prev.date){sd.count=0;sd.lastDate=prev.date;}localStorage.setItem('manahij-streak',JSON.stringify(sd));}
function getStreak(){return JSON.parse(localStorage.getItem('manahij-streak')||'{"count":0}').count;}
function launchConfetti(){const canvas=document.getElementById('confettiCanvas');if(!canvas)return;canvas.style.display='block';const ctx=canvas.getContext('2d');canvas.width=window.innerWidth;canvas.height=window.innerHeight;const particles=[];const colors=['#E65100','#FF8F00','#FFA726','#FFE0B2','#FFCC80','#BF360C'];for(let i=0;i<120;i++){particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height-canvas.height,w:Math.random()*10+5,h:Math.random()*6+3,color:colors[Math.floor(Math.random()*colors.length)],vx:(Math.random()-0.5)*4,vy:Math.random()*3+2,rot:Math.random()*360,rotSpeed:(Math.random()-0.5)*10});}let frame=0;function draw(){ctx.clearRect(0,0,canvas.width,canvas.height);particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.rot+=p.rotSpeed;ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rot*Math.PI/180);ctx.fillStyle=p.color;ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);ctx.restore();});frame++;if(frame<120)requestAnimationFrame(draw);else{ctx.clearRect(0,0,canvas.width,canvas.height);canvas.style.display='none';}}draw();}

function renderQuiz(){const t=T[lang];document.getElementById('quizContainer').innerHTML=QUIZ.map((q,i)=>`<div class="quiz-question scroll-reveal" id="quiz-q-${i}"><div class="quiz-q-text">${i+1}. ${q[lang]}</div><div class="quiz-options"><button class="quiz-opt" onclick="selectQuizOpt(${i},2)">${t.yes}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},1)">${t.sometimes}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},0)">${t.no}</button></div></div>`).join('')+`<button class="quiz-submit" onclick="submitQuiz()">${t.submitQuiz}</button>`;document.getElementById('quizResult').classList.add('hidden');window._quizAnswers={};}
function selectQuizOpt(qi,val){window._quizAnswers[qi]=val;document.querySelectorAll(`#quiz-q-${qi} .quiz-opt`).forEach((o,oi)=>{o.classList.toggle('selected',[2,1,0][oi]===val);});playSound('click');}
function submitQuiz(){const ans=window._quizAnswers||{};if(Object.keys(ans).length<QUIZ.length){showToast(lang==='ar'?'أجب على جميع الأسئلة':lang==='fr'?'Repondez a toutes les questions':'Answer all questions');return;}const inv=[1,3];let score=0;Object.entries(ans).forEach(([qi,v])=>{score+=inv.includes(parseInt(qi))?(2-v):v;});const max=QUIZ.length*2;const pct=Math.round(score/max*100);let emoji,title,desc;if(pct>=75){emoji='⚖️';title=lang==='ar'?'ممتاز!':lang==='fr'?'Excellent !':'Excellent!';desc=lang==='ar'?'لديك فهم عميق للاقتصاد الإسلامي.':lang==='fr'?'Vous avez une comprehension profonde.':'You have deep understanding.';}else if(pct>=50){emoji='📖';title=lang==='ar'?'جيد':lang==='fr'?'Bien':'Good';desc=lang==='ar'?'واصل التعلم عن الاقتصاد الإسلامي.':lang==='fr'?'Continuez a apprendre.':'Keep learning.';}else{emoji='🔄';title=lang==='ar'?'حان وقت التعلم':lang==='fr'?'Il est temps d\'apprendre':'Time to Learn';desc=lang==='ar'?'راجع البطاقات.':lang==='fr'?'Relisez les cartes.':'Review the cards.';}const r=document.getElementById('quizResult');r.classList.remove('hidden');r.innerHTML=`<div class="qr-emoji">${emoji}</div><div class="qr-score">${pct}%</div><div class="qr-title">${title}</div><div class="qr-desc">${desc}</div><button class="quiz-submit" onclick="renderQuiz()" style="margin-top:16px">${T[lang].quizAgain}</button>`;r.scrollIntoView({behavior:'smooth'});playSound('success');}

function renderAbout(){const about={ar:{disclaimerTitle:'⚠️ تنبيه مهم',disclaimer:'لست عالماً ولا مفتياً. هذا جهد متواضع من مسلم يحب كتب الشيخ الغزالي. ليست فتوى.',authorName:'الشيخ محمد الغزالي',authorDates:'١٩١٧ — ١٩٩٦',authorBio:'عالم ومفكر إسلامي مصري. ألّف أكثر من ٩٤ كتاباً. درس في الأزهر.',bookTitle:'عن الكتاب',bookDesc:'"الإسلام والمناهج الاشتراكية" يقارن فيه الشيخ الغزالي بين النظام الاقتصادي الإسلامي والأنظمة الاشتراكية. يبيّن أن الإسلام نظام وسط يحمي الملكية الفردية ويفرض العدالة الاجتماعية من خلال الزكاة والوقف والتكافل.',sourcesTitle:'المصادر',sources:['كتاب "الإسلام والمناهج الاشتراكية" — الشيخ محمد الغزالي','القرآن الكريم','صحيح البخاري ومسلم'],contact:'تواصل: abdelhak.bourdim@gmail.com'},en:{disclaimerTitle:'⚠️ Important Notice',disclaimer:'I am not a scholar. This is a humble effort. Not a fatwa.',authorName:'Sheikh Mohammed al-Ghazali',authorDates:'1917 — 1996',authorBio:'Egyptian Islamic scholar and thinker. Author of 94+ books. Al-Azhar graduate.',bookTitle:'About the Book',bookDesc:'"Islam and Socialist Systems" compares the Islamic economic system with socialist systems. It shows Islam is a moderate system that protects private property and enforces social justice through zakat, waqf, and solidarity.',sourcesTitle:'Sources',sources:['"Islam and Socialist Systems" — Sheikh Mohammed al-Ghazali','The Holy Quran','Sahih al-Bukhari and Muslim'],contact:'Contact: abdelhak.bourdim@gmail.com'},fr:{disclaimerTitle:'⚠️ Avis Important',disclaimer:'Je ne suis ni savant ni mufti. C\'est un effort humble. Ce n\'est pas une fatwa.',authorName:'Sheikh Mohammed al-Ghazali',authorDates:'1917 — 1996',authorBio:'Savant et penseur islamique egyptien. Auteur de plus de 94 livres. Diplome d\'Al-Azhar.',bookTitle:'A Propos du Livre',bookDesc:'"L\'Islam et les Systemes Socialistes" compare le systeme economique islamique avec les systemes socialistes. Il montre que l\'Islam est un systeme modere qui protege la propriete privee et impose la justice sociale.',sourcesTitle:'Sources',sources:['"L\'Islam et les Systemes Socialistes" — Sheikh Mohammed al-Ghazali','Le Saint Coran','Sahih al-Bukhari et Muslim'],contact:'Contact : abdelhak.bourdim@gmail.com'}};const a=about[lang];document.getElementById('aboutContainer').innerHTML=`<div class="about-disclaimer"><div class="about-disclaimer-title">${a.disclaimerTitle}</div><p>${a.disclaimer}</p></div><div class="about-author"><span class="about-author-icon">📚</span><div class="about-author-info"><div class="about-author-name">${a.authorName}</div><div class="about-author-dates">${a.authorDates}</div><div class="about-author-bio">${a.authorBio}</div></div></div><div class="about-section"><div class="about-section-title">${a.bookTitle}</div><p class="about-text">${a.bookDesc}</p></div><div class="about-section"><div class="about-section-title">${a.sourcesTitle}</div>${a.sources.map(s=>`<p class="about-text">&#8226; ${s}</p>`).join('')}</div><div class="about-section"><p class="about-text">${a.contact}</p></div>`;}

function renderHelp(){const h={ar:[{title:'⚠️ تنبيه',body:'لست عالماً. هذا جهد متواضع.'},{title:'📚 المصادر',body:'كتاب "الإسلام والمناهج الاشتراكية" للشيخ محمد الغزالي.'},{title:'✨ المميزات',body:'ثلاث لغات، ٣ أنماط، ٢٠ بطاقة، ٦ مقارنات، تتبع العادات، اختبار.'}],en:[{title:'⚠️ Disclaimer',body:'I am not a scholar. This is a humble effort.'},{title:'📚 Sources',body:'"Islam and Socialist Systems" by Sheikh al-Ghazali.'},{title:'✨ Features',body:'Three languages, 3 themes, 20 cards, 6 comparisons, habit tracker, quiz.'}],fr:[{title:'⚠️ Avertissement',body:'Je ne suis pas un savant.'},{title:'📚 Sources',body:'"L\'Islam et les Systemes Socialistes" par Sheikh al-Ghazali.'},{title:'✨ Fonctionnalites',body:'Trois langues, 3 themes, 20 cartes, 6 comparaisons, suivi habitudes, quiz.'}]};document.getElementById('helpBody').innerHTML=h[lang].map(i=>`<div class="help-item"><div class="help-item-title">${i.title}</div><div>${i.body}</div></div>`).join('');}
function renderDuas(){document.getElementById('duaPanelContent').innerHTML=DUAS.map(d=>{const dd=d[lang];return `<div class="dua-item"><div class="dua-item-label">${dd.label}</div><div class="dua-item-ar">${dd.text}</div><div class="dua-item-tr">${dd.tr}</div></div>`;}).join('');}

function initScrollReveal(){if(!('IntersectionObserver' in window))return;window._scrollObserver=new IntersectionObserver(e=>{e.forEach(en=>{if(en.isIntersecting){en.target.classList.add('revealed');window._scrollObserver.unobserve(en.target);}});},{threshold:0.08,rootMargin:'0px 0px -40px 0px'});document.querySelectorAll('.scroll-reveal:not(.revealed)').forEach(el=>window._scrollObserver.observe(el));document.querySelectorAll('.tab').forEach(tab=>{tab.addEventListener('click',()=>setTimeout(()=>{document.querySelectorAll('.scroll-reveal:not(.revealed)').forEach(el=>window._scrollObserver.observe(el));},100));});}
function initKeyboardNav(){document.addEventListener('keydown',e=>{if(e.key==='Escape'){const hp=document.getElementById('helpPanel');if(!hp.classList.contains('hidden')){toggleHelp();return;}const dp=document.getElementById('duaPanel');if(!dp.classList.contains('hidden')){toggleDuaPanel();return;}document.querySelectorAll('.principle-card.open').forEach(c=>c.classList.remove('open'));}if(e.key==='ArrowRight'||e.key==='ArrowLeft'){const cp=document.getElementById('panel-cards');if(!cp||!cp.classList.contains('active'))return;if(document.activeElement&&document.activeElement.id==='cardsSearch')return;e.preventDefault();const cards=Array.from(document.querySelectorAll('.principle-card')).filter(c=>c.style.display!=='none');if(!cards.length)return;if(currentCardIdx>=0&&currentCardIdx<cards.length)cards[currentCardIdx].classList.remove('open');const dir=(document.documentElement.dir==='rtl')?(e.key==='ArrowRight'?-1:1):(e.key==='ArrowRight'?1:-1);currentCardIdx=Math.max(0,Math.min(cards.length-1,currentCardIdx+dir));cards[currentCardIdx].classList.add('open');cards[currentCardIdx].scrollIntoView({behavior:'smooth',block:'center'});playSound('click');}});}

function toggleCard(id){const c=document.getElementById(id);if(c){c.classList.toggle('open');playSound('click');}}
function toggleHelp(){document.getElementById('helpPanel').classList.toggle('hidden');playSound('click');}
function toggleDuaPanel(){document.getElementById('duaPanel').classList.toggle('hidden');playSound('click');}
function showToast(msg){const t=document.getElementById('toast');const m=document.getElementById('toastMsg');if(t&&m){m.textContent=msg;t.style.display='block';setTimeout(()=>t.style.display='none',2500);}}
function initScrollTop(){const btn=document.getElementById('scrollTop');window.addEventListener('scroll',()=>{if(btn)btn.classList.toggle('visible',window.scrollY>300);});}
const AudioCtx=window.AudioContext||window.webkitAudioContext;let audioCtx;
function playSound(type){try{if(!audioCtx)audioCtx=new AudioCtx();const osc=audioCtx.createOscillator();const gain=audioCtx.createGain();osc.connect(gain);gain.connect(audioCtx.destination);gain.gain.value=0.06;if(type==='click'){osc.frequency.value=800;osc.type='sine';gain.gain.value=0.04;}else if(type==='success'){osc.frequency.value=523;osc.type='sine';}else if(type==='theme'){osc.frequency.value=440;osc.type='triangle';gain.gain.value=0.05;}osc.start();osc.stop(audioCtx.currentTime+0.1);}catch(e){}}
(function(){let tX=0,tY=0;const tabOrder=['home','cards','comparisons','habits','quiz','about'];document.addEventListener('touchstart',e=>{tX=e.changedTouches[0].screenX;tY=e.changedTouches[0].screenY;},{passive:true});document.addEventListener('touchend',e=>{const dx=e.changedTouches[0].screenX-tX;const dy=e.changedTouches[0].screenY-tY;if(Math.abs(dx)<50||Math.abs(dy)>Math.abs(dx))return;const isRTL=document.documentElement.dir==='rtl';const at=document.querySelector('.tab.active');if(!at)return;const ci=tabOrder.indexOf(at.dataset.tab);if(ci<0)return;let ni=isRTL?(dx>0?ci+1:ci-1):(dx<0?ci+1:ci-1);if(ni>=0&&ni<tabOrder.length){const nt=document.querySelector(`.tab[data-tab="${tabOrder[ni]}"]`);if(nt)nt.click();}},{passive:true});})();
function startTicker(){var el=document.getElementById('tickerText');if(!el)return;var tips={ar:['🟠 ٢٠ بطاقة عن الاقتصاد الإسلامي','⚖️ الإسلام نظام وسط عادل','💰 الزكاة نظام عدالة سبق عصره','🏗️ الوقف استثمار أبدي','🤲 اللّهُمّ بارِك في أرزاقنا','💡 Powered by workshop-diy.org'],en:['🟠 20 cards on Islamic economics','⚖️ Islam is a just moderate system','💰 Zakat: a system ahead of its time','🏗️ Waqf: an eternal investment','🤲 O God, bless our provisions','💡 Powered by workshop-diy.org'],fr:['🟠 20 cartes sur l\'economie islamique','⚖️ L\'Islam est un systeme juste et modere','💰 La Zakat : un systeme en avance','🏗️ Le Waqf : un investissement eternel','🤲 O Dieu, benis nos subsistances','💡 Powered by workshop-diy.org']};var l=document.documentElement.lang||'ar';var msgs=tips[l]||tips.ar;var txt=msgs.join('  ✦  ');el.innerHTML='<span class="tc">'+txt+'  ✦  </span><span class="tc" aria-hidden="true">'+txt+'  ✦  </span>';el.style.animation='tickerMarquee '+Math.max(25,txt.length*0.12)+'s linear infinite';}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',startTicker)}else{startTicker()}
